sql:
SELECT name
FROM nonprofits
WHERE parent_nonprofit_id IS NOT NULL;

SELECT SUM(revenue) AS total_revenue
FROM financial_data
WHERE year = (SELECT MAX(year) FROM financial_data);

SELECT nonprofit_id, name 
FROM nonprofits
WHERE parent_nonprofit_id IS NOT NULL;

external_knowledge:
- "Substantial amount of grants" refers to nonprofits with more than 1000 grants between 2022 and 2023;
- "Healthy financial status" implies a positive net income for the year 2023;
- "Recent year" refers to the year 2023;
- The results are ordered from the organization with the highest grant count to the one with the lowest grant count.

sql:
SELECT registration_date, name 
FROM nonprofits 
WHERE nonprofit_id = 1;

SELECT name
FROM nonprofits
WHERE annual_budget > (SELECT AVG(annual_budget) FROM nonprofits);

SELECT year, average_salary AS typical_pay, highest_salary AS best_earnings, lowest_salary AS worst_earnings
FROM employee_data
GROUP BY year;

external_knowledge:
- 'Size in terms of workforce' refers to the number of employees;
- 'Nonprofit entities' are organizational units within the nonprofits table;
- 'Involved in projects' implies having records in the program_data table;
- 'Benefited from financial support' means having records in the grants table.

sql:
SELECT n.name, t.type_name, n.contact_email
FROM nonprofits n
INNER JOIN nonprofit_types t ON n.nonprofit_type_id = t.nonprofit_type_id;

SELECT name, number_of_employees, legal_structure, mission_statement
FROM nonprofits
ORDER BY number_of_employees DESC;

SELECT nonprofit_id, name, registration_date
FROM nonprofits
ORDER BY registration_date DESC;

external_knowledge:
- "when they were formed" refers to the registration date;
- "their locations" indicate the addresses;
- "what kind of nonprofits they are" corresponds to the type name;
- "their yearly spending" means the annual budget;
- "the extent of their operational reach" is represented by the geographic scope; 
- "how many people work for them" refers to the number of employees.

sql:
SELECT program_name, budget
FROM program_data
WHERE budget = (SELECT MAX(budget) FROM program_data);

SELECT n.name, g.grant_amount 
FROM nonprofits n 
JOIN grants g ON n.nonprofit_id = g.nonprofit_id;
